// Script for n8n workflow to simplify Google Ads API response
// This version extracts necessary data from the nested JSON structure

const items = $input.all();
const cleanedData = [];

for (const item of items) {
  const data = item.json;
  const cleaned = {};

  // --- Campaign Details ---
  // Extract campaign name and parse campaign ID from the resource path
  if (data.campaign) {
    cleaned.campaign = data.campaign.name;
    // resourceName format: "customers/+1234567890/campaigns/+1234567890"
    // The last part is the campaign ID
    cleaned.campaignId = data.campaign.resourceName?.split('/').pop();
  }

  // --- Ad Group Details ---
  // Extract basic info related to the ad group
  if (data.adGroup) {
    cleaned.adGroup = data.adGroup.name;
    cleaned.adGroupId = data.adGroup.id;
  }

  // --- Performance Data ---
  // Convert numeric metric values and calculate cost in USD
  if (data.metrics) {
    cleaned.clicks = parseInt(data.metrics.clicks || 0);
    cleaned.impressions = parseInt(data.metrics.impressions || 0);
    cleaned.conversions = parseFloat(data.metrics.conversions || 0);
    cleaned.allConversions = parseFloat(data.metrics.allConversions || 0);

    // Convert micros unit to actual cost
    const costMicros = parseInt(data.metrics.costMicros || 0);
    cleaned.costMicros = costMicros;
    cleaned.costUSD = parseFloat((costMicros / 1000000).toFixed(2));
  }

  // --- Search Query Info ---
  // Extract the user search term and its current status
  if (data.searchTermView) {
    cleaned.searchTerm = data.searchTermView.searchTerm;
    cleaned.status = data.searchTermView.status;
  }

  // --- Time Segmentation ---
  // Identify which date the data belongs to
  if (data.segments) {
    cleaned.date = data.segments.date;
  }

  // --- Additional Calculations ---
  // Calculate CTR (click-through rate)
  if (cleaned.impressions > 0) {
    cleaned.ctr = ((cleaned.clicks / cleaned.impressions) * 100).toFixed(2) + '%';
  } else {
    cleaned.ctr = '0.00%';
  }

  // Calculate CPC (cost per click)
  if (cleaned.clicks > 0 && cleaned.costUSD > 0) {
    cleaned.cpc = (cleaned.costUSD / cleaned.clicks).toFixed(2);
  } else {
    cleaned.cpc = '0.00';
  }

  cleanedData.push({ json: cleaned });
}

return cleanedData;

// Input: array of items with conversion and performance metrics
// Output: aggregated totals by search term + campaign + ad group

const combined = {};

for (const item of items) {
  const d = item.json;
  // Unique identifier for this combination of search term, campaign, and ad group
  const key = `${d.searchTerm}_${d.campaignId}_${d.adGroupId}`;

  if (!combined[key]) {
    // First occurrence of this combination: create initial record
    combined[key] = {
      searchTerm: d.searchTerm,
      campaign: d.campaign,
      campaignId: d.campaignId,
      adGroup: d.adGroup,
      adGroupId: d.adGroupId,
      status: d.status,
      // Start all metric counters at zero
      clicks: 0,
      impressions: 0,
      costMicros: 0,
      costUSD: 0,
      conversions: 0,
      allConversions: 0
    };
  }

  // Accumulate metrics for this combination
  combined[key].clicks += d.clicks || 0;
  combined[key].impressions += d.impressions || 0;
  combined[key].costMicros += d.costMicros || 0;
  combined[key].costUSD += d.costUSD || 0;
  combined[key].conversions += d.conversions || 0;
  combined[key].allConversions += d.allConversions || 0;
}

// Transform the object into an array for output
return Object.values(combined).map(x => ({ json: x }));

// Input: items[0].json.output (structured LLM output)
// This version prepares a Slack block payload using the POST method

const data = items[0].json.output;

const blocks = [];

// Header section
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `${data.reportTitle}`,
    emoji: true
  }
});

// Date and period information
blocks.push({
  type: "section",
  fields: [
    { type: "mrkdwn", text: `*Date:*\n${data.date}` },
    { type: "mrkdwn", text: `*Period:*\n${data.period}` }
  ]
});

// Summary section
blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `${data.summary}` }
});

// Total ad wastage
blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `*Total Ad Wastage:* *$${data.totalAdWastageUSD} USD*` }
});

blocks.push({ type: "divider" });

// SECTION 1: Recommended negative keywords
if (data.recommendations && data.recommendations.length > 0) {
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*Recommended Negative Keywords to Add*" }
  });

  for (const rec of data.recommendations) {
    const keywordList = rec.negativeKeywords.map(k => `• \`${k}\``).join('\n');
    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*Campaign:* ${rec.campaign} (ID: ${rec.campaignId})\n*Ad Group:* ${rec.adGroup} (ID: ${rec.adGroupId})\n\n${keywordList}`
      }
    });
  }
  blocks.push({ type: "divider" });
}

// SECTION 2: Keywords for manual review (conditional)
if (data.keywordsForReview && data.keywordsForReview.length > 0) {
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*Keywords for Manual Review (Generated Conversions)*" }
  });

  for (const reviewItem of data.keywordsForReview) {
    const reviewText = `*Search Term:* \`${reviewItem.searchTerm}\`\n*Cost:* $${reviewItem.costUSD} USD\n*Conversions:* ${reviewItem.conversions}\n*Reason:* _${reviewItem.reason}_`;
    blocks.push({
      type: "section",
      text: { type: "mrkdwn", text: reviewText }
    });
  }
  blocks.push({ type: "divider" });
}

// SECTION 3: Confirmation buttons for POST method
if (data.recommendations && data.recommendations.length > 0) {

  // Prepare a JSON payload to send in the button's 'value' field
  const payload = JSON.stringify({
    recommendations: data.recommendations
  });

  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: "*Should the recommended keywords be excluded?*" }
  });

  blocks.push({
    type: "actions",
    elements: [
      {
        type: "button",
        text: { type: "plain_text", text: "Yes, exclude them" },
        style: "primary",
        action_id: "approve_exclusions",
        value: payload
      },
      {
        type: "button",
        text: { type: "plain_text", text: "No, ignore" },
        style: "danger",
        action_id: "reject_exclusions"
      }
    ]
  });
}

// Return the blocks payload
return [
  {
    json: {
      blocksUi: { blocks }
    }
  }
];
